          </div>

          <div className="p-6 space-y-6">
            {/* Client Selector */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 block">ربط الطلب بعميل (اختياري)</label>
              <div className="relative">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                <input 
                  type="text" 
                  placeholder="ابحث عن العميل..." 
                  className="w-full pr-10 pl-4 py-2.5 bg-gray-50 border border-gray-100 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                  value={selectedClient}
                  onChange={(e) => setSelectedClient(e.target.value)}
                />
              </div>
            </div>

            <div className="min-h-[200px] border-y border-gray-50 py-4">
              {cart.length === 0 ? (
