                        <p className="text-xs text-indigo-600 font-bold">{item.price} ر.س</p>
                      </div>
                      <div className="flex items-center gap-3 bg-gray-50 px-2 py-1 rounded-lg">
                        <button onClick={() => removeFromCart(item.name)} className="text-gray-400 hover:text-rose-500"><Minus size={14} /></button>
                        <span className="text-xs font-bold w-4 text-center">{item.quantity}</span>
