                    <div className="space-y-2">
                      <label className="text-xs font-bold text-gray-500">وقت الانتهاء</label>
                      <input 
                        type="time"
                        className="w-full bg-gray-50 border border-gray-200 rounded-xl px-2 py-3 outline-none focus:ring-2 focus:ring-indigo-500 text-center"
                        value={bookingData.endTime}
                        onChange={(e) => setBookingData({...bookingData, endTime: e.target.value})}
                      />
                    </div>
                  </div>
                </div>
              )}

              {/* Price Calculation Card */}
              <div className="bg-slate-50 p-6 rounded-3xl border border-gray-100 flex items-center justify-between">
