                </div>
                <div className="text-left">
                  <span className="text-3xl font-black text-indigo-600">{calculatePrice()}</span>
                  <span className="text-sm font-bold text-slate-900 mr-1">ر.ع</span>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex gap-4">
                <button 
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 py-4 border border-gray-200 rounded-2xl text-gray-400 font-bold hover:bg-gray-50 transition-colors"
                >
                  إلغاء
                </button>
                <button 
                  disabled={(!foundClient && !isRegisteringNew) || !bookingData.room || (isRegisteringNew && !bookingData.clientName)}
                  className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-[0.98]"
                  onClick={() => {
                    const identifier = phoneSearch;
                    const clientName = foundClient ? foundClient.name : bookingData.clientName;
                    alert(`تم تأكيد الحجز بنجاح!\nالعميل: ${clientName}\nرقم الهاتف: ${identifier}`);
                    setIsModalOpen(false);
                  }}
                >
                  <CheckCircle2 size={20} />
                  تأكيد الحجز بالرقم
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Info Card */}
      <div className="flex items-center gap-4 p-6 bg-indigo-50 border border-indigo-100 rounded-2xl">
        <div className="w-12 h-12 bg-white rounded-xl shadow-sm flex items-center justify-center text-indigo-600 flex-shrink-0">
          <Phone size={24} />
        </div>
        <div className="flex-1">
          <h4 className="font-bold text-indigo-900">نظام الحجز المعتمد على الهاتف</h4>
          <p className="text-sm text-indigo-700 opacity-80 leading-relaxed">
            لضمان دقة البيانات، يتم تعريف كافة الحجوزات برقم الهاتف. يمكنك البحث عن أي عميل برقم هاتفه أو تسجيل رقم جديد مباشرة.
          </p>
        </div>
      </div>
    </div>
  );
};

