import React, { useState } from 'react';
import { Coffee, Plus, Minus, ShoppingBag, Search, CheckCircle2 } from 'lucide-react';
import { CAFE_MENU } from '../constants';

const CafeSystem: React.FC = () => {
  const [cart, setCart] = useState<any[]>([]);
  const [selectedClient, setSelectedClient] = useState<string>('');

  const addToCart = (item: any) => {
    const existing = cart.find(i => i.name === item.name);
    if (existing) {
      setCart(cart.map(i => i.name === item.name ? { ...i, quantity: i.quantity + 1 } : i));
    } else {
      setCart([...cart, { ...item, quantity: 1 }]);
    }
  };

  const removeFromCart = (name: string) => {
    const existing = cart.find(i => i.name === name);
    if (existing && existing.quantity > 1) {
      setCart(cart.map(i => i.name === name ? { ...i, quantity: i.quantity - 1 } : i));
    } else {
      setCart(cart.filter(i => i.name !== name));
    }
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0) / 10;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 animate-in fade-in duration-700">
      {/* Menu Area */}
      <div className="lg:col-span-2 space-y-8">
        <header className="flex flex-col gap-1">
          <h2 className="text-3xl font-black text-[#2C2A3A] font-serif">قائمة كوفيكس</h2>
          <p className="text-[#6E6E6E] text-sm">مزيج من الفخامة في كل كوب</p>
        </header>

        <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
          {['الكل', 'مشروبات مختصة', 'باردة', 'حلويات فاخرة', 'سناكس'].map((cat, i) => (
            <button key={i} className={`px-6 py-2.5 rounded-full text-[11px] font-black uppercase tracking-widest border transition-all whitespace-nowrap ${i === 0 ? 'bg-[#2C2A3A] text-white border-[#2C2A3A]' : 'bg-white text-[#6E6E6E] border-[#E8E2DE] hover:border-[#D8A08A] hover:text-[#D8A08A]'}`}>
              {cat}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
          {CAFE_MENU.map((item, idx) => (
            <button 
              key={idx}
              onClick={() => addToCart(item)}
              className="bg-white p-6 rounded-[28px] border border-[#E8E2DE] shadow-sm hover:shadow-xl hover:border-[#D8A08A]/30 transition-all text-right group relative overflow-hidden"
            >
              <div className="absolute -right-4 -bottom-4 w-16 h-16 bg-[#F4E9E4] rounded-full group-hover:scale-[3] transition-transform duration-700 opacity-50" />
              <div className="relative">
                <div className="w-14 h-14 bg-[#2C2A3A] text-[#D8A08A] rounded-2xl flex items-center justify-center mb-5 group-hover:scale-110 transition-transform shadow-lg shadow-black/10">
                  <Coffee size={26} strokeWidth={2.5} />
                </div>
                <h3 className="font-bold text-lg text-[#2C2A3A] font-serif">{item.name}</h3>
                <p className="text-[#D8A08A] font-black text-xl mt-2 italic">{(item.price / 10).toFixed(3)} <span className="text-[10px] uppercase not-italic">ر.ع</span></p>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Cart Area */}
      <div className="lg:col-span-1">
        <div className="bg-white rounded-[40px] border border-[#E8E2DE] shadow-2xl overflow-hidden sticky top-10">
          <div className="p-8 bg-[#2C2A3A] text-white text-center">
            <div className="w-16 h-16 bg-[#D8A08A] rounded-2xl mx-auto flex items-center justify-center mb-4 shadow-xl shadow-black/20">
              <ShoppingBag size={28} />
            </div>
            <h3 className="text-xl font-black font-serif italic tracking-tight">طلبك الخاص</h3>
            <p className="text-white/40 text-[10px] uppercase tracking-widest mt-1 font-bold">كوفيكس بوتيك</p>
          </div>

          <div className="p-8 space-y-8">
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase tracking-widest text-[#6B4F45] block">ربط العميل بالرقم</label>
              <div className="relative">
                <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-[#D8A08A]" size={18} />
                <input 
                  type="text" 
                  placeholder="ابحث عن العميل..." 
                  className="w-full pr-12 pl-6 py-4 bg-[#F4E9E4]/40 border border-[#E8E2DE] rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-[#D8A08A] transition-all"
                  value={selectedClient}
                  onChange={(e) => setSelectedClient(e.target.value)}
