                      <div className="flex items-center gap-4 bg-[#F4E9E4]/50 p-2 rounded-xl">
                        <button onClick={() => removeFromCart(item.name)} className="text-[#6E6E6E] hover:text-rose-500 transition-colors"><Minus size={16} strokeWidth={3} /></button>
                        <span className="text-sm font-black text-[#2C2A3A] w-6 text-center">{item.quantity}</span>
