];

const ADDITIONAL_SERVICES = [
  { id: 'coffee', name: 'باقة ضيافة قهوة', icon: Coffee, price: 2.500 },
  { id: 'print', name: 'خدمات طباعة', icon: Printer, price: 1.000 },
