                            <div className="flex-1">
                              <p className="text-sm font-black text-[#2C2A3A]">{item.name}</p>
                              <p className="text-[11px] text-[#D8A08A] font-bold">{(calculateItemTotal(item) / 10).toFixed(3)} ر.ع</p>
